namespace {

ModelError make_err(ModelError::Kind k, std::string detail) {
  return ModelError{k, std::move(detail)};
}

bool is_constraint_op(parse::Op op) noexcept {
  return op == parse::Op::EqConstraint || op == parse::Op::LtConstraint ||
         op == parse::Op::GtConstraint || op == parse::Op::DefineParam;
}

// vech-index for a column-major lower-triangle of a (p × p) symmetric
// matrix: vech_index(p, r, c) for r >= c gives the row position of (r, c)
// in the vech vector. Order: (0,0), (1,0), ..., (p-1,0), (1,1), (2,1), ...
inline Eigen::Index vech_index(Eigen::Index p, Eigen::Index r, Eigen::Index c) noexcept {
  return c * p - (c * (c - 1)) / 2 + (r - c);
}

inline Eigen::Index vech_len(Eigen::Index p) noexcept {
  return p * (p + 1) / 2;
}

}  // namespace

model_expected<ModelEvaluator>
ModelEvaluator::build(const spec::LatentStructure& pt, const MatrixRep& rep) {
  if (rep.dims.empty()) {
    return std::unexpected(make_err(
        ModelError::Kind::EmptyMatrix,
        "MatrixRep has no blocks"));
  }
  if (rep.cell_for_row.size() != pt.size()) {
    return std::unexpected(make_err(
        ModelError::Kind::UnknownVariable,
        "cell_for_row length doesn't match LatentStructure size"));
  }

  ModelEvaluator out;

  // Per-block buffers.
  out.blocks_.resize(rep.dims.size());
  for (std::size_t b = 0; b < rep.dims.size(); ++b) {
    auto& bs = out.blocks_[b];
    bs.p = rep.dims[b].n_observed;
    bs.m = rep.dims[b].n_latent;
    bs.Lambda  = Eigen::MatrixXd::Zero(bs.p, std::max<std::int16_t>(bs.m, 1));
    bs.Theta   = Eigen::MatrixXd::Zero(bs.p, bs.p);
    bs.Psi     = Eigen::MatrixXd::Zero(std::max<std::int16_t>(bs.m, 1),
                                       std::max<std::int16_t>(bs.m, 1));
    bs.Beta    = Eigen::MatrixXd::Zero(std::max<std::int16_t>(bs.m, 1),
                                       std::max<std::int16_t>(bs.m, 1));
    bs.ImB     = Eigen::MatrixXd::Zero(std::max<std::int16_t>(bs.m, 1),
                                       std::max<std::int16_t>(bs.m, 1));
    bs.ImB_inv = Eigen::MatrixXd::Zero(std::max<std::int16_t>(bs.m, 1),
                                       std::max<std::int16_t>(bs.m, 1));
    bs.LamA    = Eigen::MatrixXd::Zero(bs.p, std::max<std::int16_t>(bs.m, 1));
    bs.Mid     = Eigen::MatrixXd::Zero(std::max<std::int16_t>(bs.m, 1),
                                       std::max<std::int16_t>(bs.m, 1));
    bs.Sigma   = Eigen::MatrixXd::Zero(bs.p, bs.p);
    if (bs.m == 0) {
      bs.Lambda.resize(bs.p, 0);
      bs.Psi.resize(0, 0);  bs.Beta.resize(0, 0);
      bs.ImB.resize(0, 0);  bs.ImB_inv.resize(0, 0);
      bs.LamA.resize(bs.p, 0);  bs.Mid.resize(0, 0);
    }
  }

  // Walk rows; build the write table.
  std::int32_t max_free = 0;
  for (std::size_t i = 0; i < pt.size(); ++i) {
    if (is_constraint_op(pt.op[i])) continue;
    if (pt.free[i] > max_free) max_free = pt.free[i];
    const Cell& c = rep.cell_for_row[i];
    if (!c.used) continue;       // P5.1 sentinel for ~ / ~1 rows

    CellWrite w;
    w.mat       = static_cast<std::uint8_t>(c.mat);
    w.row       = c.row;
    w.col       = c.col;
    w.block     = c.block;
    w.is_free   = (pt.free[i] != 0);
    w.free_idx  = pt.free[i];
    w.fixed_value = pt.fixed_value[i];
    if (!std::isfinite(w.fixed_value)) {
      // fixed_value can be NaN for "compute later" rows. For pure CFA, the
      // only case where a row is fixed AND fixed_value=NaN is the fixed.x exo
      // rows; those aren't reached in CFA-only models. Treat NaN as 0.0 for
      // now and revisit when fixed.x machinery is exercised numerically.
      w.fixed_value = 0.0;
    }
    out.writes_.push_back(w);
    if (w.is_free && w.free_idx > max_free) max_free = w.free_idx;
  }

  // Structural cells from MatrixRep — phantom-Λ identity entries for
  // ov.y / ov.x in Reduced form. Stored as fixed CellWrites with value
  // taken from the StructuralCell.
  for (const auto& sc : rep.structural_cells) {
    CellWrite w;
    w.mat   = static_cast<std::uint8_t>(sc.mat);
    w.row   = sc.row;
    w.col   = sc.col;
    w.block = sc.block;
    w.is_free     = false;
    w.free_idx    = 0;
    w.fixed_value = sc.value;
    out.structural_writes_.push_back(w);
  }
  out.n_free_ = static_cast<std::size_t>(max_free);

  // Mark blocks that have any mean-structure (Nu / Alpha) cells, and
  // allocate per-block Nu / Alpha / Mu buffers. Blocks without ~1 rows
  // keep zero-sized buffers and return an empty `mu` in ImpliedMoments.
  for (const auto& w : out.writes_) {
    const auto mat = static_cast<MatId>(w.mat);
    if (mat == MatId::Nu || mat == MatId::Alpha) {
      out.blocks_[static_cast<std::size_t>(w.block)].has_means = true;
    }
  }
  for (auto& bs : out.blocks_) {
    if (bs.has_means) {
      bs.Nu    = Eigen::VectorXd::Zero(bs.p);
      bs.Alpha = (bs.m > 0) ? Eigen::VectorXd::Zero(bs.m)
                            : Eigen::VectorXd();
      bs.Mu    = Eigen::VectorXd::Zero(bs.p);
    }
  }
  return out;
}

model_expected<void>
ModelEvaluator::assemble(Eigen::Ref<const Eigen::VectorXd> theta) const {
  if (static_cast<std::size_t>(theta.size()) != n_free_) {
    return std::unexpected(make_err(
        ModelError::Kind::UnknownVariable,
        std::string("theta has size ") + std::to_string(theta.size()) +
            "; ModelEvaluator expects " + std::to_string(n_free_)));
  }
  // Reset matrices to zero (cheap; small matrices in v0).
  for (auto& bs : blocks_) {
    if (bs.Lambda.size() > 0) bs.Lambda.setZero();
    if (bs.Theta.size()  > 0) bs.Theta.setZero();
    if (bs.Psi.size()    > 0) bs.Psi.setZero();
    if (bs.Beta.size()   > 0) bs.Beta.setZero();
    if (bs.Nu.size()     > 0) bs.Nu.setZero();
    if (bs.Alpha.size()  > 0) bs.Alpha.setZero();
  }
  auto apply = [&](const CellWrite& w, double v) {
    auto& bs = blocks_[static_cast<std::size_t>(w.block)];
    switch (static_cast<MatId>(w.mat)) {
      case MatId::Lambda: bs.Lambda(w.row, w.col) = v; break;
      case MatId::Theta:
        bs.Theta(w.row, w.col) = v;
        if (w.row != w.col) bs.Theta(w.col, w.row) = v;
        break;
      case MatId::Psi:
        bs.Psi(w.row, w.col) = v;
        if (w.row != w.col) bs.Psi(w.col, w.row) = v;
        break;
      case MatId::Beta:
        bs.Beta(w.row, w.col) = v;   // not symmetric
        break;
      case MatId::Nu:
        bs.Nu(w.row) = v;
        break;
      case MatId::Alpha:
        bs.Alpha(w.row) = v;
        break;
    }
  };
  // Structural (fixed identity etc.) cells first, then partable cells.
  for (const auto& w : structural_writes_) apply(w, w.fixed_value);
  for (const auto& w : writes_) {
    const double v = w.is_free ? theta[w.free_idx - 1] : w.fixed_value;
    apply(w, v);
  }
  return {};
}

model_expected<ImpliedMoments>
ModelEvaluator::sigma(Eigen::Ref<const Eigen::VectorXd> theta) const {
  if (auto e = assemble(theta); !e.has_value()) {
    return std::unexpected(e.error());
  }
  compute_intermediates(true, true);
  return current_moments();
}

void ModelEvaluator::compute_intermediates(bool with_sigma, bool with_mu) const {
  for (auto& bs : blocks_) {
    if (bs.m > 0) {
      bs.ImB     = -bs.Beta;
      bs.ImB.diagonal().array() += 1.0;
      bs.ImB_inv = bs.ImB.inverse();
      bs.LamA.noalias() = bs.Lambda * bs.ImB_inv;
      if (with_sigma) {
        bs.Mid.noalias()  = bs.ImB_inv * bs.Psi * bs.ImB_inv.transpose();
        bs.Sigma.noalias() = bs.LamA * bs.Psi * bs.LamA.transpose() + bs.Theta;
      }
    } else if (with_sigma) {
      bs.Sigma = bs.Theta;
    }
    if (with_mu && bs.has_means) {
      if (bs.m > 0 && bs.Alpha.size() > 0) {
        bs.Mu.noalias() = bs.Nu + bs.LamA * bs.Alpha;
      } else {
        bs.Mu = bs.Nu;
      }
    }
  }
}

ImpliedMoments ModelEvaluator::current_moments() const {
  ImpliedMoments out;
  out.sigma.reserve(blocks_.size());
  out.mu.reserve(blocks_.size());
  for (const auto& bs : blocks_) {
    out.sigma.push_back(bs.Sigma);
    if (bs.has_means) {
      out.mu.push_back(bs.Mu);
    } else {
      out.mu.emplace_back();
    }
  }
  return out;
}

model_expected<Eigen::MatrixXd>
ModelEvaluator::dsigma_dtheta(Eigen::Ref<const Eigen::VectorXd> theta) const {
  if (auto e = assemble(theta); !e.has_value()) {
    return std::unexpected(e.error());
  }
  compute_intermediates(true, false);
  return current_dsigma_dtheta();
}

Eigen::MatrixXd ModelEvaluator::current_dsigma_dtheta() const {
  Eigen::Index total_vech = 0;
  for (const auto& bs : blocks_) total_vech += vech_len(static_cast<Eigen::Index>(bs.p));

  Eigen::MatrixXd J(total_vech, static_cast<Eigen::Index>(n_free_));
  J.setZero();

  // Pre-compute per-block helpers used by multiple parameter types.
  //   LamA = Λ (I-B)⁻¹       — used by Λ, Β, Ψ derivatives
  //   LamA_Psi = LamA · Ψ    — used by Λ derivatives
  //   Mid = (I-B)⁻¹ Ψ (I-B)⁻ᵀ — used by Β derivatives
  // (sigma() left LamA / Mid populated in BlockState; we re-use those.)
  std::vector<Eigen::MatrixXd> Lam_Mid(blocks_.size());
  for (std::size_t b = 0; b < blocks_.size(); ++b) {
    const auto& bs = blocks_[b];
    if (bs.m > 0) Lam_Mid[b].noalias() = bs.Lambda * bs.Mid;
  }

  // Per-block vech offsets.
  std::vector<Eigen::Index> block_off(blocks_.size() + 1, 0);
  for (std::size_t b = 0; b < blocks_.size(); ++b) {
    block_off[b + 1] = block_off[b] +
                       vech_len(static_cast<Eigen::Index>(blocks_[b].p));
  }

  for (const auto& w : writes_) {
    if (!w.is_free) continue;
    const Eigen::Index k = static_cast<Eigen::Index>(w.free_idx - 1);
    const std::size_t  b = static_cast<std::size_t>(w.block);
    const auto& bs = blocks_[b];
    const Eigen::Index p = static_cast<Eigen::Index>(bs.p);
    const Eigen::Index off = block_off[b];

    switch (static_cast<MatId>(w.mat)) {
      case MatId::Lambda: {
        // Σ = LamA Ψ LamAᵀ + Θ.  ∂Σ[r,s]/∂Λ_ij touches LamA only via Λ:
        //   ∂LamA[r,c]/∂Λ_ij = δ_ri (I-B)⁻¹[j,c]  ≡ row i of (I-B)⁻¹ at column c, scaled by δ_ri.
        // Thus ∂(LamA Ψ LamAᵀ)[r,s]/∂Λ_ij = δ_ri (LamA Ψ)[s, j']·...  — but the
        // simpler closed form using LamA_Psi:
        //   ∂Σ[r,s]/∂Λ_ij = δ_ri (LamA Ψ ImB_inv^T)[s, j] + δ_si (LamA Ψ ImB_inv^T)[r, j]
        // For pure CFA (B=0) ImB_inv = I and this collapses to the Λ Ψ formula
        // we shipped in P6.1.
        const Eigen::Index i = static_cast<Eigen::Index>(w.row);
        const Eigen::Index j = static_cast<Eigen::Index>(w.col);
        const Eigen::MatrixXd& LM = Lam_Mid[b];
        for (Eigen::Index s = 0; s < p; ++s) {
          for (Eigen::Index r = s; r < p; ++r) {
            double val = 0.0;
            if (r == i) val += LM(s, j);
            if (s == i) val += LM(r, j);
            J(off + vech_index(p, r, s), k) = val;
          }
        }
        break;
      }
      case MatId::Theta: {
        const Eigen::Index i = static_cast<Eigen::Index>(w.row);
        const Eigen::Index j = static_cast<Eigen::Index>(w.col);
        if (i == j) {
          J(off + vech_index(p, i, i), k) = 1.0;
        } else {
          const Eigen::Index r = std::max(i, j);
          const Eigen::Index s = std::min(i, j);
          J(off + vech_index(p, r, s), k) = 1.0;
        }
        break;
      }
      case MatId::Psi: {
        // Σ = LamA Ψ LamAᵀ + Θ ⇒ ∂Σ[r,s]/∂Ψ_ij = LamA[r,i] LamA[s,j] (+ swap if off-diag)
        const Eigen::Index i = static_cast<Eigen::Index>(w.row);
        const Eigen::Index j = static_cast<Eigen::Index>(w.col);
        for (Eigen::Index s = 0; s < p; ++s) {
          for (Eigen::Index r = s; r < p; ++r) {
            double val = bs.LamA(r, i) * bs.LamA(s, j);
            if (i != j) val += bs.LamA(r, j) * bs.LamA(s, i);
            J(off + vech_index(p, r, s), k) = val;
          }
        }
        break;
      }
      case MatId::Beta: {
        // ∂(I-B)⁻¹/∂B_ij = (I-B)⁻¹ E_ij (I-B)⁻¹
        // Let A = (I-B)⁻¹, M = A Ψ Aᵀ. Then
        //   ∂M/∂B_ij = A E_ij M + M E_jiᵀ Aᵀ = (col_i of A) · (row_j of M) + transpose
        // ∂Σ/∂B_ij = Λ ∂M/∂B_ij Λᵀ
        // Using LamA = Λ A and LamA_Psi = LamA Ψ:
        //   ∂Σ[r,s]/∂B_ij = LamA[r, i] · (LamA_Psi · Aᵀ)[s, j] + (LamA_Psi · Aᵀ)[r, j] · LamA[s, i]
        //                 = LamA[r, i] · Lam_Mid[s, j] + Lam_Mid[r, j] · LamA[s, i]
        // (where Lam_Mid = Λ Mid = LamA Ψ (I-B)⁻ᵀ as above).
        const Eigen::Index i = static_cast<Eigen::Index>(w.row);
        const Eigen::Index j = static_cast<Eigen::Index>(w.col);
        const Eigen::MatrixXd& LM = Lam_Mid[b];
        for (Eigen::Index s = 0; s < p; ++s) {
          for (Eigen::Index r = s; r < p; ++r) {
            const double val = bs.LamA(r, i) * LM(s, j) +
                               LM(r, j) * bs.LamA(s, i);
            J(off + vech_index(p, r, s), k) = val;
          }
        }
        break;
      }
      case MatId::Nu:
      case MatId::Alpha:
        // ∂Σ/∂ν = ∂Σ/∂α = 0 — mean-structure params don't appear in Σ.
        // Their contribution to the gradient comes through the mean term
        // of F_ML and is handled by ML separately (via `dmu_dtheta`).
        break;
    }
  }
  return J;
}

model_expected<Eigen::MatrixXd>
ModelEvaluator::dmu_dtheta(Eigen::Ref<const Eigen::VectorXd> theta) const {
  if (auto e = assemble(theta); !e.has_value()) {
    return std::unexpected(e.error());
  }
  compute_intermediates(false, false);
  return current_dmu_dtheta();
}

Eigen::MatrixXd ModelEvaluator::current_dmu_dtheta() const {
  bool any_means = false;
  for (const auto& bs : blocks_) if (bs.has_means) { any_means = true; break; }
  if (!any_means) return Eigen::MatrixXd();   // sentinel: no mean structure

  // Per-block row offsets in the stacked dμ matrix.
  std::vector<Eigen::Index> block_off(blocks_.size() + 1, 0);
  for (std::size_t b = 0; b < blocks_.size(); ++b) {
    block_off[b + 1] = block_off[b] +
                       static_cast<Eigen::Index>(blocks_[b].p);
  }
  const Eigen::Index total_p = block_off.back();
  Eigen::MatrixXd Jmu(total_p, static_cast<Eigen::Index>(n_free_));
  Jmu.setZero();

  // Precompute Aα per block (used by Λ and B derivatives).
  std::vector<Eigen::VectorXd> A_alpha(blocks_.size());
  for (std::size_t b = 0; b < blocks_.size(); ++b) {
    auto& bs = blocks_[b];
    if (bs.has_means && bs.m > 0 && bs.Alpha.size() > 0) {
      A_alpha[b].noalias() = bs.ImB_inv * bs.Alpha;
    }
  }

  for (const auto& w : writes_) {
    if (!w.is_free) continue;
    const Eigen::Index k = static_cast<Eigen::Index>(w.free_idx - 1);
    const std::size_t  b = static_cast<std::size_t>(w.block);
    const auto& bs = blocks_[b];
    if (!bs.has_means) continue;             // block contributes nothing
    const Eigen::Index off = block_off[b];
    const Eigen::Index p   = static_cast<Eigen::Index>(bs.p);
    const Eigen::Index r   = static_cast<Eigen::Index>(w.row);
    const Eigen::Index c   = static_cast<Eigen::Index>(w.col);

    switch (static_cast<MatId>(w.mat)) {
      case MatId::Nu:
        // ∂μ/∂ν_i = e_i.
        Jmu(off + r, k) = 1.0;
        break;
      case MatId::Alpha:
        // ∂μ/∂α_j = LamA[:, j].
        Jmu.col(k).segment(off, p) = bs.LamA.col(r);
        break;
      case MatId::Lambda: {
        // ∂μ/∂Λ_{r,c} = e_r · (Aα)_c.   Zero if α is absent.
        if (A_alpha[b].size() == 0) break;
        Jmu(off + r, k) = A_alpha[b](c);
        break;
      }
      case MatId::Beta: {
        // ∂μ/∂B_{r,c} = LamA[:, r] · (Aα)_c.  Zero if α is absent.
        if (A_alpha[b].size() == 0) break;
        Jmu.col(k).segment(off, p) = bs.LamA.col(r) * A_alpha[b](c);
        break;
      }
      case MatId::Psi:
      case MatId::Theta:
        // ∂μ/∂{Ψ,Θ} = 0.
        break;
    }
  }
  return Jmu;
}

model_expected<Evaluation>
ModelEvaluator::evaluate(Eigen::Ref<const Eigen::VectorXd> theta,
                         bool with_sigma_jacobian,
                         bool with_mu_jacobian) const {
  if (auto e = assemble(theta); !e.has_value()) {
    return std::unexpected(e.error());
  }
  compute_intermediates(true, true);

  Evaluation out;
  out.moments = current_moments();
  if (with_sigma_jacobian) out.J_sigma = current_dsigma_dtheta();
  if (with_mu_jacobian) out.J_mu = current_dmu_dtheta();
  return out;
}

model_expected<AssembledMatrices>
ModelEvaluator::assembled(Eigen::Ref<const Eigen::VectorXd> theta) const {
  // Reuse sigma() for the assembly path — it leaves all the per-block
  // intermediates (Lambda, Psi, Theta, Beta, ImB_inv, LamA, Mid) populated
  // as a side effect. Then snapshot them by value.
  if (auto sm = sigma(theta); !sm.has_value()) {
    return std::unexpected(sm.error());
  }
  AssembledMatrices out;
  out.blocks.reserve(blocks_.size());
  for (const auto& bs : blocks_) {
    BlockMatrices bm;
    bm.Lambda = bs.Lambda;
    bm.Psi    = bs.Psi;
    bm.Theta  = bs.Theta;
    bm.Beta   = bs.Beta;
    bm.A      = bs.ImB_inv;
    bm.LamA   = bs.LamA;
    bm.Mid    = bs.Mid;
    bm.Nu     = bs.Nu;
    bm.Alpha  = bs.Alpha;
    out.blocks.push_back(std::move(bm));
  }
  return out;
}

std::vector<ParamLocation>
ModelEvaluator::param_locations() const {
  std::vector<ParamLocation> out(n_free_);
  for (const auto& w : writes_) {
    if (!w.is_free) continue;
    const std::size_t k = static_cast<std::size_t>(w.free_idx - 1);
    if (k >= out.size()) continue;       // shouldn't happen; defensive
    out[k].mat   = static_cast<MatId>(w.mat);
    out[k].row   = w.row;
    out[k].col   = w.col;
    out[k].block = w.block;
  }
  return out;
}

